-- department_faculty_import.sql
-- Run this in Supabase SQL Editor to create and fill the faculty table used by departments.html.

create table if not exists public.department_faculty (
  id bigint generated by default as identity primary key,
  created_at timestamptz not null default now(),
  response_timestamp timestamptz,
  name text not null,
  email text not null unique,
  department text not null,
  course_type text,
  designation text,
  location text,
  monday text,
  tuesday text,
  wednesday text,
  thursday text,
  friday text,
  sem_1 text,
  sem_2 text,
  sem_3 text,
  sem_4 text,
  sem_5 text,
  sem_6 text,
  sem_7 text,
  sem_8 text
);

alter table public.department_faculty enable row level security;
grant usage on schema public to anon;
grant select on public.department_faculty to anon;

drop policy if exists "Anyone can view department faculty" on public.department_faculty;
create policy "Anyone can view department faculty"
on public.department_faculty
for select
to anon
using (true);

